// withProxyPaymentID sets the ID field of the mutation.
func withProxyPaymentID(id int64) proxypaymentOption {
	return func(m *ProxyPaymentMutation) {
		var (
			err   error
			once  sync.Once
			value *ProxyPayment
		)
		m.oldValue = func(ctx context.Context) (*ProxyPayment, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().ProxyPayment.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

